function mcq(q:string,opts:string[],c:number,ex:string){return{type:'multiple_choice',question:q,options:opts,correct:c,explanation:ex}}
function tf(q:string,ans:boolean,ex:string){return{type:'true_false',question:q,answer:ans,explanation:ex}}
function fb(q:string,ans:string,ex:string){return{type:'fill_blank',question:q,answer:ans,explanation:ex}}

