console.log('\n📖 Module 2: Language of Tech');
const m2 = modules[1];
const m2Lessons = [
  {title:'What is a Website vs a Web App?',slug:'website-vs-webapp',order:1,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"A website is like a newspaper — you read it but can't change it. A web app is like a spreadsheet — you interact with it, enter data, and it responds. Google.com (search) is a web app. A blog is a website. Facebook is a web app. A restaurant menu page is a website. The difference matters because building a web APP requires a backend (server + database), while a simple website might only need a frontend.",keyPoints:["Website = static content you read (blog, portfolio, menu)","Web app = interactive, responds to your actions (Gmail, Twitter, Notion)","Websites: mainly frontend (HTML, CSS, JS)","Web apps: frontend + backend + database","Most things you'll build with AI are web apps"],realWorldExample:"When you scroll Instagram (web app), every like, comment, and follow is processed by a backend server and stored in a database. A restaurant's simple menu page (website) just displays text and images.",eli10:"A website is like a poster on a wall — you look at it. A web app is like a video game — you click buttons and things happen!"}),
    demo:undefined,
    quiz:JSON.stringify([mcq("Which is a web APP?",["A blog post","A restaurant menu","Gmail","A Wikipedia article"],2,"Gmail lets you compose, send, receive, and organize emails — that's interactive = web app."),mcq("What extra parts does a web app need compared to a simple website?",["Just HTML","A backend server and database","Only CSS","A mobile app"],1,"Web apps need servers to process logic and databases to store user data.")]),
    challenge:undefined},

  {title:'Frontend: What Users See',slug:'frontend-explained',order:2,difficulty:'BEGINNER' as const,estimatedMinutes:6,
    concept:JSON.stringify({story:"The frontend is everything you can see and touch in a browser. It's built with three languages working together like a team: HTML is the skeleton (structure), CSS is the clothing (style), and JavaScript is the brain (interactivity). When you use Lovable or v0, the AI writes all three for you. But understanding what they do helps you give better prompts!",keyPoints:["HTML = Structure (headings, paragraphs, buttons, forms)","CSS = Style (colors, fonts, spacing, layout, animations)","JavaScript = Behavior (click handlers, form validation, dynamic content)","React, Vue, Angular = frameworks that organize JS for complex apps","Frontend runs in the USER'S browser, not on a server"],realWorldExample:"When you see a blue 'Buy Now' button: HTML created the button element. CSS made it blue and rounded. JavaScript makes something happen when you click it.",eli10:"Building a frontend is like building a house. HTML is the walls and rooms (structure). CSS is the paint and decorations (making it pretty). JavaScript is the electricity and plumbing (making things work when you flip a switch)."}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What does CSS do?",["Creates the page structure","Adds interactivity","Controls visual style (colors, fonts, layout)","Stores data"],2,"CSS = Cascading Style Sheets. It controls how things LOOK: colors, sizes, spacing, animations."),mcq("What does JavaScript do in the frontend?",["Structures the page","Styles the page","Makes things interactive (clicks, forms, animations)","Stores data in a database"],2,"JavaScript handles interactivity: what happens when you click buttons, submit forms, scroll, etc."),fb("The three frontend languages are HTML, ___, and JavaScript.","CSS","HTML provides structure, CSS provides style, and JavaScript provides interactivity.")]),
    challenge:undefined},

  {title:'Backend: The Engine Room',slug:'backend-explained',order:3,difficulty:'BEGINNER' as const,estimatedMinutes:6,
    concept:JSON.stringify({story:"The backend is like the kitchen in a restaurant. Customers (users) see the dining room (frontend), but all the real work happens in the kitchen — cooking food (processing data), storing recipes (database), checking IDs (authentication). When you log into Instagram, the backend checks your password, loads your feed from the database, and sends it to your phone. Common backend languages: Node.js (JavaScript), Python, Java, Go.",keyPoints:["Backend = server-side code users never see","Handles: authentication, data processing, business logic","Common languages: Node.js, Python, Java, Ruby, Go","Communicates with frontend via APIs","Connects to databases to store/retrieve data","Runs on servers (someone else's computer)"],realWorldExample:"When you post a photo on Instagram: your phone (frontend) sends the image to Instagram's servers (backend), which saves it to a database, processes it, and then shows it to your followers.",eli10:"The backend is like the kitchen in a restaurant. You (the user) sit in the dining room and order food. The kitchen cooks it and brings it to you. You never see the kitchen, but without it, there's no food!"}),
    demo:undefined,
    quiz:JSON.stringify([mcq("Where does the backend run?",["In the user's browser","On a server","On the user's phone","In the CSS file"],1,"Backend code runs on servers — remote computers that process requests and return responses."),mcq("What does the backend handle?",["Page colors and fonts","Authentication, data storage, and business logic","Only images","Only HTML"],1,"Backend handles the serious stuff: verifying users, saving data, processing payments, etc.")]),
    challenge:undefined},

  {title:'How Frontend Talks to Backend (APIs)',slug:'apis-explained',order:4,difficulty:'BEGINNER' as const,estimatedMinutes:7,
    concept:JSON.stringify({story:"APIs (Application Programming Interfaces) are how the frontend and backend communicate. Think of it like ordering pizza. You (frontend) call the pizza place (backend) and say 'I want a large pepperoni.' They make it and deliver it. The PHONE CALL is the API. Technically: the frontend sends an HTTP REQUEST to the backend's API endpoint, and the backend sends back a RESPONSE with data (usually in JSON format). The 4 main request types: GET (read), POST (create), PUT (update), DELETE (remove).",keyPoints:["API = the 'phone line' between frontend and backend","Frontend sends REQUESTS, backend sends RESPONSES","GET = read data, POST = create data, PUT = update, DELETE = remove","Data is sent in JSON format (like a structured text file)","APIs also connect apps to external services (Google Maps, Stripe, OpenAI)","Every time you load a page, dozens of API calls happen behind the scenes"],realWorldExample:"When you open Uber: GET request fetches nearby drivers. POST request creates a ride when you tap 'Request'. PUT updates your destination. DELETE cancels the ride.",eli10:"An API is like a waiter in a restaurant. You (frontend) tell the waiter what you want. The waiter goes to the kitchen (backend), gets your food, and brings it back. The waiter is the API!"}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What is an API?",["A programming language","A way for frontend and backend to communicate","A type of database","A design tool"],1,"API = Application Programming Interface. It's the communication bridge between different parts of an app."),mcq("Which HTTP method CREATES new data?",["GET","POST","DELETE","CSS"],1,"POST creates new data. GET reads, PUT updates, DELETE removes."),fb("APIs send data in ___ format, which looks like structured text with key-value pairs.","JSON","JSON (JavaScript Object Notation) is the universal format for API data exchange.")]),
    challenge:undefined},

  {title:'Databases: Where Your Data Lives',slug:'databases-explained',order:5,difficulty:'BEGINNER' as const,estimatedMinutes:6,
    concept:JSON.stringify({story:"A database is like a super-powered spreadsheet. It stores all your app's data: user accounts, posts, messages, orders, everything. There are two main types: SQL databases (like Excel — organized rows and columns with strict rules) and NoSQL databases (like a filing cabinet — flexible, documents of different shapes). SQL examples: PostgreSQL, MySQL. NoSQL examples: MongoDB, Firebase.",keyPoints:["Database = organized storage for your app's data","SQL: rows + columns, strict structure (like Excel spreadsheets)","NoSQL: flexible documents (like filing folders)","SQL is best when data is structured and related","NoSQL is best when data varies in shape","Most vibe coding tools use PostgreSQL (SQL) or Firebase/Supabase"],realWorldExample:"Your bank uses SQL databases (strict structure for financial data). Twitter might use NoSQL (flexible for different types of content). Most apps use SQL — and that's what Lovable, Bolt, and Supabase give you.",eli10:"A database is like a giant organized bookshelf. SQL is a library where every book has to go in a specific spot. NoSQL is more like a bedroom where you can put things wherever, but it's still organized enough to find stuff!"}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What's the main difference between SQL and NoSQL?",["Speed","SQL has strict structure (tables), NoSQL is flexible (documents)","Cost","SQL is newer"],1,"SQL = strict tables with rows/columns. NoSQL = flexible documents that can have different shapes."),mcq("Which database type do most vibe coding tools use?",["NoSQL only","SQL (PostgreSQL via Supabase)","Flat files","No database"],1,"Most AI coding platforms (Lovable, Bolt) use Supabase, which is built on PostgreSQL (SQL).")]),
    challenge:undefined},

  {title:'SQL vs NoSQL: When to Use Which',slug:'sql-vs-nosql',order:6,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"Choosing SQL vs NoSQL is like choosing between a spreadsheet and a notebook. SQL (spreadsheet): Perfect when your data has a clear structure — users, orders, products. Every row looks the same. NoSQL (notebook): Great when data varies — some posts have images, some have videos, some have polls. Each 'document' can be different. Rule of thumb: if you can imagine your data in a spreadsheet → SQL. If your data is messy and varied → NoSQL. When in doubt, SQL is almost always the safe choice.",keyPoints:["SQL: Structured data, relationships between tables","NoSQL: Flexible data, each record can be different","SQL: Users, Orders, Products, Payments → perfect fit","NoSQL: Social feeds, logs, IoT data → flexible fit","When in doubt, choose SQL (safer for most apps)","Supabase (SQL) is the most common in vibe coding tools"],realWorldExample:"Airbnb uses SQL for bookings (structured: dates, prices, users). They might use NoSQL for search (flexible: location data, filters, rankings).",eli10:"SQL is like a spreadsheet — every row has the same columns (name, age, email). NoSQL is like a scrapbook — each page can have different stuff (photos, stickers, drawings, notes)."}),
    demo:undefined,
    quiz:JSON.stringify([mcq("When should you use SQL?",["When data is unstructured","When data has clear structure with relationships","When you don't need a database","For images only"],1,"SQL excels with structured, relational data: users, orders, products, etc."),tf("When in doubt, SQL is the safer default choice.",true,"SQL works for the vast majority of applications and is better supported by AI coding tools.")]),
    challenge:undefined},

  {title:'What is a Tech Stack?',slug:'what-is-tech-stack',order:7,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"A tech stack is the combination of technologies used to build an app — like a recipe listing all ingredients. A typical stack: React (frontend) + Node.js (backend) + PostgreSQL (database) + Vercel (hosting). When someone says 'What stack are you using?', they're asking about your ingredients list. Different stacks suit different needs. Vibe coding tools choose the stack for you, but knowing what they chose helps you debug and extend your app.",keyPoints:["Tech stack = combination of all technologies in your app","Frontend: React, Vue, Angular, Svelte","Backend: Node.js, Python, Ruby, Go","Database: PostgreSQL, MongoDB, Firebase","Hosting: Vercel, Netlify, AWS, Replit","AI tools pick the stack for you, but knowing it helps"],realWorldExample:"Netflix: React (frontend) + Java/Node.js (backend) + Cassandra (database) + AWS (hosting). Lovable typically generates: React + Supabase (backend + database) + Lovable hosting.",eli10:"A tech stack is like a recipe. To make a cake you need flour, eggs, sugar, and an oven. To make an app you need a frontend, backend, database, and hosting. Different cakes use different recipes!"}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What is a tech stack?",["A pile of code","The combination of technologies used to build an app","A type of database","A hosting platform"],1,"Tech stack = your app's complete ingredient list: frontend + backend + database + hosting."),fb("A typical modern stack is React (frontend) + Node.js (backend) + ___ (database) + Vercel (hosting).","PostgreSQL","PostgreSQL is the most popular database for modern web apps, used by Supabase and many AI tools.")]),
    challenge:undefined},

  {title:'Popular Stacks: MERN, Next.js, JAMstack',slug:'popular-stacks',order:8,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"Some tech stacks are so popular they have names! MERN = MongoDB + Express + React + Node.js (the classic full-stack JavaScript stack). Next.js stack = Next.js + PostgreSQL + Vercel (the modern favorite — what v0 and Lovable often generate). JAMstack = JavaScript + APIs + Markup (for fast static sites). You don't need to memorize these, but recognizing them helps you understand AI-generated code and tool documentation.",keyPoints:["MERN: MongoDB, Express, React, Node.js — all JavaScript","Next.js: React framework + PostgreSQL + Vercel — modern favorite","JAMstack: JavaScript, APIs, Markup — fast static sites","Most AI tools generate Next.js or React + Supabase","Knowing the stack name helps you search for solutions"],realWorldExample:"When Lovable builds your app, it typically uses React + TypeScript + Tailwind CSS + Supabase. That's essentially a Next.js-style stack. Bolt uses a similar combination.",eli10:"These are like famous recipes that everyone knows. Just like 'chocolate chip cookies' tells a baker everything they need to know, 'MERN stack' tells a developer what ingredients the app uses."}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What does MERN stand for?",["Modern Efficient Reactive Network","MongoDB, Express, React, Node.js","Multiple Endpoint REST Navigation","Meta Engineering Runtime Node"],1,"MERN = MongoDB (database) + Express (backend framework) + React (frontend) + Node.js (runtime)."),mcq("Which stack do most AI coding tools generate?",["LAMP (PHP)","MERN","React/Next.js + Supabase (PostgreSQL)","Ruby on Rails"],2,"Modern AI tools like Lovable and Bolt typically generate React or Next.js with Supabase.")]),
    challenge:undefined},

  {title:'URLs, Domains & DNS',slug:'urls-domains-dns',order:9,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"When you type google.com, how does your browser know where to go? DNS (Domain Name System) is the internet's phone book. It translates human-friendly names (google.com) into computer-friendly IP addresses (142.251.32.46). A URL is the full address: https://www.google.com/search?q=vibe+coding. A domain is just the name part: google.com. You buy domains from registrars like Namecheap or GoDaddy.",keyPoints:["URL = full address (https://example.com/page)","Domain = the name (example.com)","DNS = translates domains to IP addresses","IP address = the computer's actual address (like a phone number)","Buy domains from registrars ($10-15/year)","Vercel/Netlify give you free subdomains (yourapp.vercel.app)"],realWorldExample:"When you deploy on Vercel, you get a free URL like my-app.vercel.app. To use your own domain (myapp.com), you buy it and point its DNS to Vercel's servers.",eli10:"A domain name is like a nickname. Your friend's real address might be '123 Oak Street' (IP address), but you just call them 'Alex' (domain name). DNS is the directory that knows Alex lives at 123 Oak Street."}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What does DNS do?",["Designs websites","Translates domain names to IP addresses","Stores databases","Creates APIs"],1,"DNS = Domain Name System. It's the internet's phone book, turning names into addresses."),fb("A full URL like https://example.com/about has three parts: protocol (https), ___ (example.com), and path (/about).","domain","The domain is the main identifier — the 'name' of the website.")]),
    challenge:undefined},

  {title:'Hosting: Where Your App Lives',slug:'hosting-explained',order:10,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"Your app needs to live somewhere so people can access it. That 'somewhere' is a server — a computer that's always on, always connected to the internet. You don't need to buy a server! Cloud platforms rent them to you. For vibe coders, the best options are: Vercel (best for React/Next.js, free tier), Netlify (great for static sites, free tier), Replit (built-in, zero config), and Lovable (hosts for you automatically).",keyPoints:["Hosting = putting your app on a server for the world to access","You rent servers from cloud platforms","Vercel: Best for React/Next.js apps (free tier: 100GB bandwidth)","Netlify: Great for static sites (free tier generous)","Replit: Built-in hosting, zero configuration","Lovable: Hosts your app automatically","Free tiers are plenty for learning and small projects"],realWorldExample:"When you clicked 'Deploy' in Lovable, it uploaded your app to their servers. That's hosting! The URL you got points to that server.",eli10:"Hosting is like renting a locker at school for your project. You put your project in the locker (server), and anyone with the combination (URL) can see it anytime."}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What is hosting?",["Designing a website","Putting your app on a server so people can access it","Writing code","Buying a domain"],1,"Hosting = making your app accessible on the internet by running it on a server."),mcq("Which hosting platform is best for beginners?",["AWS (complex, enterprise-level)","Vercel or Lovable (free, simple, one-click deploy)","Setting up your own server","None — apps don't need hosting"],1,"Vercel and Lovable offer free tiers with one-click deployment. Perfect for beginners.")]),
    challenge:undefined},

  {title:'What is the Cloud?',slug:'what-is-cloud',order:11,difficulty:'BEGINNER' as const,estimatedMinutes:4,
    concept:JSON.stringify({story:"'The cloud' sounds mystical, but it's simple: it's just someone else's computer. When you save a photo to iCloud, it's stored on Apple's servers. When you deploy to Vercel, your app runs on Vercel's servers. The big cloud providers are AWS (Amazon), Azure (Microsoft), and GCP (Google). They have millions of servers worldwide. You rent tiny slices of these servers, pay only for what you use, and scale up if needed.",keyPoints:["The cloud = someone else's computer (servers you rent)","Big three: AWS (Amazon), Azure (Microsoft), GCP (Google)","You pay only for what you use","Can scale from 1 user to 1 million without buying hardware","Vercel, Netlify, Replit run ON TOP of these cloud providers","'Serverless' = cloud manages the server for you"],realWorldExample:"Netflix runs on AWS. When millions watch a show, AWS automatically provides more servers. When viewership drops, it scales back. You only pay for what you use.",eli10:"The cloud is like a really big garage where you can store your stuff. Instead of buying your own garage, you rent a tiny space. If you need more room, you just rent more. That's the cloud!"}),
    demo:undefined,
    quiz:JSON.stringify([tf("The cloud is just other people's computers that you rent.",true,"Despite the fancy name, cloud computing is simply renting server space from companies like Amazon, Microsoft, or Google."),mcq("What does 'serverless' mean?",["No servers are used","You don't manage the server — the cloud provider does","It runs on your local computer","It's offline"],1,"'Serverless' doesn't mean no servers — it means you don't have to manage them. The cloud handles everything.")]),
    challenge:undefined},

  {title:'Mobile Apps vs Web Apps vs PWAs',slug:'mobile-web-pwa',order:12,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"Three ways to build 'apps' for phones: Native mobile apps (Swift for iOS, Kotlin for Android) — downloaded from App Store/Play Store. Web apps — websites that work on phones (like mobile Twitter). PWAs (Progressive Web Apps) — web apps that feel native (can be 'installed', work offline, send notifications). For vibe coders, web apps and PWAs are the way to go — you build once and it works everywhere. No App Store approval needed!",keyPoints:["Native: Built for one platform (iOS or Android), best performance","Web app: Website that works on phones, one codebase for all","PWA: Web app with native-like features (install, offline, notifications)","Vibe coding mostly produces web apps (works everywhere!)","No App Store review process for web apps","React apps are automatically mobile-responsive if designed well"],realWorldExample:"Twitter.com on your phone is a PWA. It can be 'installed' to your home screen, sends notifications, and works like a native app — but it's a website!",eli10:"Native apps are like specific toys made for one kid. Web apps are like toys any kid can play with. PWAs are web toys that are SO good they feel like they were made just for you!"}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What's the best approach for vibe coders?",["Build native iOS and Android apps separately","Build a web app (works everywhere, one codebase)","Only build desktop apps","Don't build for mobile"],1,"Web apps work on all devices with one codebase. No app store approval needed. Perfect for vibe coding."),mcq("What is a PWA?",["A programming language","A web app with native-like features (install, offline, notifications)","A database type","An AI tool"],1,"PWA = Progressive Web App. It's a website that can be installed, works offline, and sends push notifications.")]),
    challenge:undefined},

  {title:'Authentication: How Apps Know Who You Are',slug:'authentication-explained',order:13,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"When you log into Instagram, how does it know it's you? Authentication! The most common flow: you enter email + password. The backend checks if they match. If yes, it gives you a 'token' (like a wristband at a concert). Your browser stores this token and shows it with every request. The server sees the wristband and says 'cool, you're allowed in.' Modern apps also support OAuth (login with Google/GitHub) and Magic Links (link sent to your email).",keyPoints:["Authentication = verifying who you are","Password + email → backend verifies → gives you a token","Token = your 'access pass' stored in the browser","JWT (JSON Web Token) = most common token format","OAuth = 'Login with Google/GitHub' (easiest for users)","Never store passwords in plain text — always hashed!"],realWorldExample:"When Lovable lets you 'Sign in with Google', that's OAuth. Google confirms your identity and tells Lovable 'yes, this person is who they say they are.'",eli10:"Authentication is like showing your ID to get into a movie. You prove who you are (password), get a ticket (token), and show the ticket to get into different rooms (pages)."}),
    demo:undefined,
    quiz:JSON.stringify([mcq("What is a token in authentication?",["A physical coin","An access pass that proves you're logged in","A password","An API key"],1,"A token is a digital 'wristband' that proves you've already verified your identity."),tf("Passwords should be stored exactly as the user types them.",false,"NEVER store plain text passwords! They must be 'hashed' (scrambled) before storage. If the database leaks, hashed passwords are unreadable.")]),
    challenge:undefined},

  {title:'Real-time vs Request-Response',slug:'realtime-vs-request',order:14,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"Most web communication is request-response: you ask for something (request), the server gives it back (response). Like sending a letter and waiting for a reply. But some features need real-time: chat messages, live notifications, stock prices, multiplayer games. For real-time, we use WebSockets — an always-open connection, like a phone call instead of letters. Supabase and Firebase both support real-time updates.",keyPoints:["Request-Response: Client asks → Server answers (like letters)","Real-time: Constant open connection (like a phone call)","WebSockets enable real-time communication","Use request-response for: loading pages, submitting forms, searching","Use real-time for: chat, notifications, live updates, collaboration","Supabase Realtime and Firebase both support this"],realWorldExample:"Google Docs is real-time — you see other people's edits as they type. A blog is request-response — you load it once, and it doesn't change until you refresh.",eli10:"Request-response is like texting — you send a message and wait for a reply. Real-time is like a phone call — you hear each other instantly, all the time!"}),
    demo:undefined,
    quiz:JSON.stringify([mcq("Which feature needs real-time communication?",["Loading a profile page","Submitting a form","Live chat messages","Searching for products"],2,"Chat requires instant delivery of messages — that's real-time via WebSockets."),mcq("What technology enables real-time web communication?",["HTML","CSS","WebSockets","DNS"],2,"WebSockets maintain a persistent connection between client and server for instant two-way communication.")]),
    challenge:undefined},

  {title:'Quiz: Can You Speak Tech Now?',slug:'speak-tech-quiz',order:15,difficulty:'BEGINNER' as const,estimatedMinutes:5,
    concept:JSON.stringify({story:"You've completed Module 2! Let's test your new vocabulary. You now know the difference between frontend and backend, how APIs connect them, what databases store, what a tech stack is, and how hosting and deployment work. This knowledge is your SUPERPOWER as a vibe coder — you can now give AI tools much more precise instructions because you understand what they're building.",keyPoints:["Frontend = what users see (HTML, CSS, JS)","Backend = server logic (Node.js, Python)","API = communication between frontend ↔ backend","Database = where data is stored (SQL vs NoSQL)","Hosting = putting your app on the internet","Tech stack = all technologies combined"],realWorldExample:"Now when an AI tool asks 'Do you want Supabase for your backend?' you know that means 'Do you want a PostgreSQL database with built-in authentication and APIs?'",eli10:"You just learned a whole new language! Like learning Spanish means you can talk to more people, learning tech-speak means you can talk to AI tools better!"}),
    demo:undefined,
    quiz:JSON.stringify([
      mcq("What's the difference between frontend and backend?",["Frontend is slower","Frontend = what users see, Backend = server logic users don't see","Frontend costs more","There is no difference"],1,"Frontend is the user interface. Backend is the invisible server processing logic."),
      fb("The four HTTP methods are GET (read), POST (create), ___ (update), and DELETE (remove).","PUT","GET reads, POST creates, PUT updates, DELETE removes. These are the four pillars of REST APIs."),
      mcq("SQL databases organize data in:",["Random piles","Rows and columns (like spreadsheets)","Alphabetical lists","Binary trees"],1,"SQL = tables with rows and columns. Each row is a record, each column is a field."),
      mcq("What translates domain names to IP addresses?",["HTTP","CSS","DNS","APIs"],2,"DNS (Domain Name System) is the internet's phone book, turning names into IP addresses."),
      tf("PWAs can work offline and be installed on phones like native apps.",true,"Progressive Web Apps support offline mode, installation, and push notifications — bridging the gap between web and native."),
      mcq("Which is NOT a hosting platform?",["Vercel","Netlify","PostgreSQL","Replit"],2,"PostgreSQL is a DATABASE, not a hosting platform. Vercel, Netlify, and Replit all provide hosting.")
    ]),
    challenge:JSON.stringify({type:"project_task",description:"Write a one-paragraph description of an app idea, using at least 5 tech terms you learned (frontend, backend, API, database, hosting, etc.). Example: 'I want to build a web app with a React frontend...'",criteria:["Uses at least 5 tech terms correctly","Describes a realistic app idea","Mentions frontend and backend","Mentions database or API"],xpBonus:50})},
];

