console.log('\n📖 Glossary');
const glossaryTerms = [
  {term:'API',definition:'Application Programming Interface — a set of rules that lets different software applications communicate with each other.',eli10:'A waiter in a restaurant. You tell the waiter what you want, the waiter tells the kitchen, and brings your food back.',category:'tech',relatedTerms:JSON.stringify(['REST','endpoint','JSON','HTTP'])},
  {term:'Frontend',definition:'The part of a website or app that users see and interact with — built with HTML, CSS, and JavaScript.',eli10:'The outside of a building — the doors, windows, and paint that everyone sees.',category:'tech',relatedTerms:JSON.stringify(['HTML','CSS','JavaScript','React'])},
  {term:'Backend',definition:'The server-side part of an application that handles logic, database operations, and authentication — invisible to users.',eli10:'The kitchen in a restaurant. You never see it, but all the important cooking happens there.',category:'tech',relatedTerms:JSON.stringify(['server','Node.js','API','database'])},
  {term:'Database',definition:'An organized collection of data stored electronically. Can be SQL (structured tables) or NoSQL (flexible documents).',eli10:'A super-organized bookshelf where you can instantly find any book.',category:'tech',relatedTerms:JSON.stringify(['SQL','NoSQL','PostgreSQL','MongoDB'])},
  {term:'HTML',definition:'HyperText Markup Language — the skeleton of every web page, defining its structure and content.',eli10:'The building blocks of a web page — like the walls and rooms of a house.',category:'tech',relatedTerms:JSON.stringify(['CSS','JavaScript','frontend','tag'])},
  {term:'CSS',definition:'Cascading Style Sheets — controls the visual appearance of web pages: colors, fonts, layout, animations.',eli10:'The paint, decorations, and furniture that make a house look nice.',category:'tech',relatedTerms:JSON.stringify(['HTML','Tailwind','responsive','styling'])},
  {term:'JavaScript',definition:'The programming language of the web. Adds interactivity to websites and can run both in browsers and on servers (Node.js).',eli10:'The electricity in a house — it makes things work when you flip switches and press buttons.',category:'tech',relatedTerms:JSON.stringify(['TypeScript','Node.js','React','frontend'])},
  {term:'React',definition:'A JavaScript library by Meta for building user interfaces. The most popular frontend framework.',eli10:'A set of pre-built LEGO pieces that make it faster to build complicated things.',category:'tech',relatedTerms:JSON.stringify(['Next.js','component','JSX','frontend'])},
  {term:'Node.js',definition:'A JavaScript runtime that lets you run JavaScript on servers (backend), not just in browsers.',eli10:'JavaScript escaped from the browser and now works in the kitchen (server) too!',category:'tech',relatedTerms:JSON.stringify(['JavaScript','Express','backend','npm'])},
  {term:'Git',definition:'A version control system that tracks changes to your code over time. Like infinite undo + save points.',eli10:'A time machine for your code. You can go back to any point in time and see what things looked like.',category:'tech',relatedTerms:JSON.stringify(['GitHub','commit','branch','repository'])},
  {term:'GitHub',definition:'A website that hosts Git repositories online. Where most open-source code lives.',eli10:'A social media site for code. People share their projects and work together.',category:'tech',relatedTerms:JSON.stringify(['Git','repository','pull request','open source'])},
  {term:'JSON',definition:'JavaScript Object Notation — a text format for storing and exchanging data. Used by virtually all APIs.',eli10:'A recipe card with clear labels. Each ingredient has a name and a value.',category:'tech',relatedTerms:JSON.stringify(['API','data','object','key-value'])},
  {term:'REST',definition:'Representational State Transfer — a standard way to design APIs using HTTP methods (GET, POST, PUT, DELETE).',eli10:'A set of rules for how to ask the waiter (API) for things. GET = look at the menu, POST = order food.',category:'tech',relatedTerms:JSON.stringify(['API','HTTP','endpoint','CRUD'])},
  {term:'Deployment',definition:'The process of taking your code and making it live on the internet for users to access.',eli10:'Putting your art project on display in the school hallway so everyone can see it.',category:'deployment',relatedTerms:JSON.stringify(['hosting','Vercel','Netlify','CI/CD'])},
  {term:'DNS',definition:'Domain Name System — translates human-readable domain names (google.com) to IP addresses (142.251.32.46).',eli10:"The internet's phone book. You look up a name and get an address.",category:'tech',relatedTerms:JSON.stringify(['domain','IP address','URL','hosting'])},
  {term:'Environment Variables',definition:'Configuration values (like API keys and passwords) stored outside your code for security.',eli10:'Secret notes you keep in a locked drawer, not taped to the fridge where everyone can see them.',category:'security',relatedTerms:JSON.stringify(['.env','secrets','API key','configuration'])},
  {term:'Prompt Engineering',definition:'The skill of writing effective instructions for AI models to get the best possible output.',eli10:'Learning exactly how to ask your super-smart robot helper to build things the way you want.',category:'tech',relatedTerms:JSON.stringify(['AI','vibe coding','context','iteration'])},
  {term:'Token',definition:'In auth: a digital pass proving identity. In AI: a unit of text (~4 characters) that models process.',eli10:'A wristband at a theme park. Once you get it, you can ride all the rides without buying tickets each time.',category:'security',relatedTerms:JSON.stringify(['JWT','authentication','session','API key'])},
  {term:'Responsive Design',definition:'Designing websites that look good on all screen sizes — phones, tablets, and desktops.',eli10:'A stretchy shirt that fits kids AND adults. The website stretches to fit any screen!',category:'design',relatedTerms:JSON.stringify(['mobile-first','CSS','media query','layout'])},
  {term:'Component',definition:'A reusable piece of UI in frameworks like React. A button, a card, a navigation bar are all components.',eli10:'A LEGO brick. You can use the same brick in many different creations.',category:'tech',relatedTerms:JSON.stringify(['React','reusable','UI','props'])},
  {term:'NPM',definition:'Node Package Manager — a tool to install and manage code libraries (packages) for JavaScript projects.',eli10:'An app store for code pieces. Instead of building everything yourself, you download pre-made parts.',category:'tech',relatedTerms:JSON.stringify(['Node.js','package','dependency','library'])},
  {term:'TypeScript',definition:'A superset of JavaScript that adds type checking — catches bugs before code runs.',eli10:'JavaScript with spell-check. It catches mistakes as you write, not after.',category:'tech',relatedTerms:JSON.stringify(['JavaScript','types','compile','strict'])},
  {term:'Supabase',definition:'An open-source Firebase alternative providing database, auth, storage, and real-time APIs. Built on PostgreSQL.',eli10:'A ready-made backend in a box. Database, user login, and file storage all included.',category:'tech',relatedTerms:JSON.stringify(['PostgreSQL','Firebase','backend','auth'])},
  {term:'Vercel',definition:'A cloud platform for deploying web applications, especially Next.js and React. Free tier available.',eli10:'A free display case on the internet where you put your website for everyone to see.',category:'deployment',relatedTerms:JSON.stringify(['deployment','Next.js','hosting','CDN'])},
  {term:'Tailwind CSS',definition:'A utility-first CSS framework that lets you style elements with pre-built class names instead of writing custom CSS.',eli10:'Instead of mixing paint colors yourself, you have thousands of pre-mixed colors to choose from.',category:'tech',relatedTerms:JSON.stringify(['CSS','styling','utility','responsive'])},
];
